        "GettingStarted": {
            "title": "GettingStarted",
            "text": "\\define lingo-base() $:/language/ControlPanel/Basics/\nж¬ўиҝҺдҪҝз”Ё ~TiddlyWiki еҸҠеҸӮдёҺ ~TiddlyWiki зӨҫзҫӨ\n\nејҖе§Ӣе°ҶйҮҚиҰҒиө„и®Ҝеӯҳж”ҫдәҺ ~TiddlyWiki д№ӢеүҚпјҢзЎ®и®ӨжӮЁеҸҜд»ҘеҸҜйқ ең°дҝқеӯҳеҸҳжӣҙжҳҜеҫҲйҮҚиҰҒзҡ„гҖӮиҜҰз»Ҷиө„и®ҜиҜ·еҸӮйҳ… https://tiddlywiki.com/#GettingStarted\n\n!! и®ҫзҪ®жӯӨ ~TiddlyWiki\n\n<div class=\"tc-control-panel\">\n\n|<$link to=\"$:/SiteTitle\"><<lingo Title/Prompt>></$link> |<$edit-text tiddler=\"$:/SiteTitle\" default=\"\" tag=\"input\"/> |\n|<$link to=\"$:/SiteSubtitle\"><<lingo Subtitle/Prompt>></$link> |<$edit-text tiddler=\"$:/SiteSubtitle\" default=\"\" tag=\"input\"/> |\n|<$link to=\"$:/DefaultTiddlers\"><<lingo DefaultTiddlers/Prompt>></$link> |<<lingo DefaultTiddlers/TopHint>><br> <$edit tag=\"textarea\" tiddler=\"$:/DefaultTiddlers\"/><br>//<<lingo DefaultTiddlers/BottomHint>>// |\n</div>\n\nиҜ·еҸӮйҳ…[[жҺ§еҲ¶еҸ°|$:/ControlPanel]]жҹҘзңӢжӣҙеӨҡйҖүйЎ№гҖӮ"
        },
        "$:/language/Help/build": {
            "title": "$:/language/Help/build",
            "description": "иҮӘеҠЁжү§иЎҢе·Ій…ҚзҪ®зҡ„е‘Ҫд»Ө",
            "text": "з”ҹжҲҗжҢҮе®ҡзҡ„з”ҹжҲҗзӣ®ж ҮдёәеҪ“еүҚ wikiгҖӮиӢҘжңӘжҢҮе®ҡд»»дҪ•з”ҹжҲҗзӣ®ж ҮпјҢеҲҷз”ҹжҲҗжүҖжңүеҸҜз”Ёзҡ„зӣ®ж ҮгҖӮ\n\n```\n--build <target> [<target> ...]\n```\n\nз”ҹжҲҗзӣ®ж ҮеңЁ wiki ж–Үд»¶еӨ№зҡ„ `tiddlywiki.info` ж–Үд»¶дёӯе®ҡд№үгҖӮ\n"
        },
        "$:/language/Help/clearpassword": {
            "title": "$:/language/Help/clearpassword",
            "description": "жё…йҷӨз”ЁдәҺеҗҺз»ӯеҠ еҜҶзҡ„еҜҶз Ғ",
            "text": "жё…йҷӨз”ЁдәҺеҗҺз»ӯеҠ еҜҶзҡ„еҜҶз Ғ\n\n```\n--clearpassword\n```\n"
        },
        "$:/language/Help/default": {
            "title": "$:/language/Help/default",
            "text": "\\define commandTitle()\n$:/language/Help/$(command)$\n\\end\n```\nз”Ёжі•: tiddlywiki [<wikifolder>] [--<command> [<args>...]...]\n```\n\nеҸҜз”Ёзҡ„е‘Ҫд»Өпјҡ\n\n<ul>\n<$list filter=\"[commands[]sort[title]]\" variable=\"command\">\n<li><$link to=<<commandTitle>>><$macrocall $name=\"command\" $type=\"text/plain\" $output=\"text/plain\"/></$link>: <$transclude tiddler=<<commandTitle>> field=\"description\"/></li>\n</$list>\n</ul>\n\nеҸ–еҫ—е…ідәҺжҹҗдёӘе‘Ҫд»Өзҡ„иҜҰз»Ҷеё®еҠ©пјҡ\n\n```\ntiddlywiki --help <command>\n```\n"
        },
        "$:/language/Help/deletetiddlers": {
            "title": "$:/language/Help/deletetiddlers",
            "description": "еҲ йҷӨдёҖз»„жқЎзӣ®",
            "text": "<<.from-version \"5.1.20\">> еҲ йҷӨз”ұзӯӣйҖүеҷЁж ҮиҜҶзҡ„дёҖз»„жқЎзӣ®гҖӮ\n\n```\n--deletetiddlers <filter>\n```\n"
        },
        "$:/language/Help/editions": {
            "title": "$:/language/Help/editions",
            "description": "еҲ—еҮәеҸҜз”Ёзҡ„ TiddlyWiki зүҲжң¬",
            "text": "еҲ—еҮәеҸҜз”ЁзүҲжң¬зҡ„еҗҚз§°е’ҢжҸҸиҝ°гҖӮжӮЁеҸҜд»Ҙз”Ё `--init` е‘Ҫд»ӨеҲӣе»әдёҖдёӘжҢҮе®ҡзүҲжң¬зҡ„ж–°з»ҙеҹәгҖӮ\n\n```\n--editions\n```\n"
        },
        "$:/language/Help/fetch": {
            "title": "$:/language/Help/fetch",
            "description": "йҖҡиҝҮзҪ‘еқҖд»Һз»ҙеҹәж’·еҸ–жқЎзӣ®",
            "text": "йҖҡиҝҮ HTTP/HTTPS ж’·еҸ–дёҖдёӘжҲ–еӨҡдёӘж–Үд»¶пјҢе№¶еҜје…ҘеҢ№й…ҚзӯӣйҖүеҷЁзҡ„жқЎзӣ®пјҢеҸҜйҖүзҡ„иҪ¬жҚўдј е…Ҙзҡ„еҗҚз§°гҖӮ\n\n```\n--fetch file <url> <import-filter> <transform-filter>\n--fetch files <url-filter> <import-filter> <transform-filter>\n--fetch raw-file <url> <transform-filter>\n--fetch raw-files <url-filter> <transform-filter>\n```\n\n \"file\" е’Ң \"files\" йҖүйЎ№ж’·еҸ–жҢҮе®ҡзҡ„ж–Үд»¶пјҢе№¶е°қиҜ•еҜје…Ҙе…¶дёӯзҡ„жқЎзӣ®пјҲдёҺе°Ҷж–Үд»¶жӢ–еҠЁеҲ°жөҸи§ҲеҷЁи§ҶзӘ—дёӯзҡ„еӨ„зҗҶзӣёеҗҢпјүгҖӮ \"raw-file\" е’Ң \"raw-files\" еҸҳйҖүйЎ№ж’·еҸ–жҢҮе®ҡзҡ„ж–Үд»¶пјҢе№¶е°ҶеҺҹе§Ӣж–Үд»¶иө„ж–ҷеӯҳеӮЁдәҺжқЎзӣ®пјҢиҖҢдёҚеҘ—з”ЁеҜје…ҘйҖ»иҫ‘гҖӮ\n\nдҪҝз”Ё \"file\" and \"raw-file\" йҖүйЎ№дёәд»…ж’·еҸ–еҚ•дёӘж–Үд»¶пјҢдё”з¬¬дёҖдёӘеҸӮж•°дёәиҰҒиҜ»еҸ–ж–Үд»¶зҡ„зҪ‘еқҖгҖӮ\n\nдҪҝз”Ё \"files\" е’Ң \"raw-files\" йҖүйЎ№дёәж’·еҸ–еӨҡдёӘж–Үд»¶пјҢдё”з¬¬дёҖдёӘеҸӮж•°жҳҜдёҖдёӘдә§з”ҹиҰҒиҜ»еҸ–ж–Үд»¶зҡ„зҪ‘еқҖжё…еҚ•зҡ„зӯӣйҖүеҷЁгҖӮдҫӢеҰӮпјҢз»ҷе®ҡж Үзӯҫдёә \"remote-server\" зҡ„дёҖз»„е…·жңүеӯ—ж®ө \"url\" зҡ„жқЎзӣ®пјҢзӯӣйҖүеҷЁ `[tag[remote-server]get[url]]` е°ҶеҸ–еӣһжүҖжңүеҸҜз”Ёзҡ„зҪ‘еқҖгҖӮ\n\nеҜ№дәҺ \"file\" е’Ң \"files\" йҖүйЎ№пјҢthe `<import-filter>` еҸӮж•°жҢҮе®ҡдёҖдёӘзӯӣйҖүеҷЁпјҢз”ЁдәҺзЎ®е®ҡиҰҒеҜје…Ҙе“ӘдәӣжқЎзӣ®гҖӮеҰӮжһңжңӘжҸҗдҫӣпјҢеҲҷй»ҳи®Өдёә `[all[tiddlers]]`гҖӮ\n\nеҜ№дәҺжүҖжңүйҖүйЎ№пјҢ`<transform-filter>` еҸӮж•°жҢҮе®ҡдёҖдёӘеҸҜйҖүзҡ„зӯӣйҖүеҷЁпјҢз”ЁдәҺиҪ¬жҚўеҜје…ҘжқЎзӣ®зҡ„еҗҚз§°гҖӮдҫӢеҰӮпјҢ`[addprefix[$:/myimports/]]` дјҡе°ҶеүҚзјҖ  `$:/myimports/` еҠ иҮіжҜҸдёӘеҗҚз§°гҖӮ\n\nдәҺ `--fetch` д№ӢеүҚдҪҝз”Ё `--verbose` е‘Ҫд»ӨпјҢе°ҶеңЁеҜје…Ҙжңҹй—ҙиҫ“еҮәиҝӣеәҰдҝЎжҒҜгҖӮ\n\nиҜ·жіЁж„ҸпјҢTiddlyWiki дёҚдјҡж’·еҸ–дёҖдёӘе·Із»ҸеҠ иҪҪжҸ’д»¶зҡ„ж—§зүҲжң¬гҖӮ\n\nд»ҘдёӢзӨәдҫӢд»Һ https://tiddlywiki.com еҸ–еӣһжүҖжңүйқһзі»з»ҹжқЎзӣ®пјҢе№¶е°Ҷе…¶дҝқеӯҳеҲ°дёҖдёӘ JSON ж–Үд»¶пјҡ\n\n```\ntiddlywiki --verbose --fetch file \"https://tiddlywiki.com/\" \"[!is[system]]\" \"\" --rendertiddler \"$:/core/templates/exporters/JsonFile\" output.json text/plain \"\" exportFilter \"[!is[system]]\"\n```\n\nд»ҘдёӢиҢғдҫӢд»Һ https://tiddlywiki.com еҸ–еӣһ \"favicon\" ж–Үд»¶пјҢе№¶е°Ҷе…¶дҝқеӯҳеңЁеҗҚдёә \"output.ico\" зҡ„ж–Үд»¶дёӯгҖӮиҜ·жіЁж„ҸпјҢеңЁ \"--fetch\" е‘Ҫд»Өдёӯеј•з”Ёзҡ„дёӯй—ҙжқЎзӣ® \"Icon Tiddler\"пјҢеӣ дёәе®ғиў«з”ЁдҪңиҪ¬жҚўзӯӣйҖүеҷЁжқҘжӣҝжҚўйў„и®ҫзҡ„еҗҚз§°пјҢиҖҢ \"--savetiddler\" е‘Ҫд»ӨжІЎжңүеј•еҸ·пјҢеӣ дёәе®ғжҳҜзӣҙжҺҘз”ЁдҪңж ҮйўҳгҖӮ\n\n```\ntiddlywiki --verbose --fetch raw-file \"https://tiddlywiki.com/favicon.ico\" \"[[Icon Tiddler]]\" --savetiddler \"Icon Tiddler\" output.ico\n```\n"
        },
        "$:/language/Help/help": {
            "title": "$:/language/Help/help",
            "description": "жҳҫзӨә TiddlyWiki е‘Ҫд»Өзҡ„иҜҙжҳҺ",
            "text": "жҳҫзӨәе‘Ҫд»Өзҡ„её®еҠ©ж–Үжң¬:\n\n```\n--help [<command>]\n```\n\nиӢҘзңҒз•Ҙе‘Ҫд»ӨеҗҚз§°пјҢеҲҷжҳҫзӨәеҸҜз”Ёе‘Ҫд»Өзҡ„жё…еҚ•гҖӮ\n"
        },
        "$:/language/Help/import": {
            "title": "$:/language/Help/import",
            "description": "д»Һж–Үд»¶еҜје…ҘжқЎзӣ®",
            "text": "д»Һ TiddlyWiki ж–Үд»¶ (`.html`)гҖҒ`.tiddler`гҖҒ`.tid`гҖҒ`.json` жҲ–е…¶д»–жң¬жңәж–Үд»¶еҜје…ҘжқЎзӣ®гҖӮеҝ…йЎ»жҳҺзЎ®жҢҮе®ҡи§ЈдёІеҷЁпјҢиҖҢдёҚеғҸ load е‘Ҫд»ӨпјҢд»Һж–Үд»¶жү©еұ•еҗҚжҺЁж–ӯи§ЈдёІеҷЁгҖӮ\n\n```\n--import <filepath> <deserializer> [<title>] [<encoding>]\n```\n\nж ёеҝғзҡ„и§ЈдёІеҷЁеҢ…жӢ¬пјҡ\n\n* application/javascript\n* application/json\n* application/x-tiddler\n* application/x-tiddler-html-div\n* application/x-tiddlers\n* text/html\n* text/plain\n\nеҜје…Ҙзҡ„жқЎзӣ®еҗҚз§°пјҢй»ҳи®Өдёәж–Үд»¶еҗҚгҖӮ\n\nзј–з Ғй»ҳи®Өдёә \"utf8\"пјҢдҪҶз”ЁдәҺеҜје…ҘдәҢиҝӣеҲ¶ж–Үд»¶еҸҜд»ҘжҳҜ \"base64\"гҖӮ\n\nиҜ·жіЁж„ҸпјҢTiddlyWiki дёҚдјҡеҜје…Ҙж—§зүҲжң¬зҡ„е·ІеҠ иҪҪжҸ’д»¶гҖӮ\n"
        },
        "$:/language/Help/init": {
            "title": "$:/language/Help/init",
            "description": "еҲқе§ӢеҢ–дёҖдёӘж–°зҡ„ wiki ж–Үд»¶еӨ№",
            "text": "еҲқе§ӢеҢ–дёҖдёӘз©әзҡ„ [[WikiFolder|WikiFolders]] зҡ„жҢҮе®ҡзүҲжң¬зҡ„еүҜжң¬гҖӮ\n\n```\n--init <edition> [<edition> ...]\n```\n\nдҫӢеҰӮпјҡ\n\n```\ntiddlywiki ./MyWikiFolder --init empty\n```\n\nжіЁж„Ҹпјҡ\n\n* иӢҘжңүйңҖиҰҒпјҢе°ҶеҲӣе»ә wiki ж–Үд»¶еӨ№зӣ®еҪ•\n* е…¶дёӯ \"edition\" й»ҳи®Өдёә ''empty''\n* иӢҘ wiki ж–Үд»¶еӨ№дёҚжҳҜз©әзҡ„пјҢеҲҷеҲқе§ӢеҢ–е‘Ҫд»Өе°ҶеӨұиҙҘ\n* еҲқе§ӢеҢ–е‘Ҫд»ӨдјҡеҲ йҷӨ 'tiddlywiki.info' ж–Үд»¶еҶ…жүҖжңү 'includeWikis' зҡ„е®ҡд№үгҖӮ\n* еҪ“жҢҮе®ҡеӨҡдёӘзүҲжң¬ж—¶пјҢиҝҷдәӣзүҲжң¬дәҺеҲқе§ӢеҢ–еҗҺпјҢе°ҶиҰҶеҶҷж—©жңҹзүҲжң¬е…ұз”Ёзҡ„жүҖжңүж–Үд»¶ (ж•…жӯӨжңҖз»Ҳзҡ„ `tiddlywiki.info` ж–Үд»¶е°ҶжҳҜд»ҺжңҖиҝ‘зҡ„зүҲжң¬еӨҚеҲ¶иҖҢеҫ—)\n* `--editions` дј еӣһжүҖжңүеҸҜз”ЁзүҲжң¬зҡ„жё…еҚ•гҖӮ\n"
        },
        "$:/language/Help/listen": {
            "title": "$:/language/Help/listen",
            "description": "дёә TiddlyWiki жҸҗдҫӣдёҖдёӘ HTTP жңҚеҠЎеҷЁжҺҘеҸЈ",
            "text": "йҖҡиҝҮ HTTP жҸҗдҫӣдёҖдёӘз»ҙеҹәжңҚеҠЎгҖӮ\n\nlisten е‘Ҫд»ӨдҪҝз”Ё[[е‘ҪеҗҚзҡ„е‘Ҫд»ӨеҸӮж•°|NamedCommandParameters]]пјҡ\n\n```\n--listen [<name>=<value>]...\n```\n\nжүҖжңүеҸӮж•°йғҪжҳҜеҸҜйҖүзҡ„, е…·жңүе®үе…Ёзҡ„й»ҳи®ӨеҖј, еҸҜд»ҘжҢүд»»ж„ҸйЎәеәҸжҢҮе®ҡгҖӮи®ӨеҸҜзҡ„еҸӮж•°жңү:\n\n* ''host'' - еҸҜйҖүзҡ„дё»жңәеҗҚз§°пјҢ (й»ҳи®Өдёә \"127.0.0.1\" жҲ–еҗҚдёә \"localhost\")\n* ''path-prefix'' - еҸҜйҖүзҡ„и·Ҝеҫ„еүҚзјҖ\n* ''port'' - дҫҰеҗ¬зҡ„еҹ еҸ·пјӣйқһж•°еҖјдјҡиў«и§ЈиҜ‘дёәдёҖдёӘзі»з»ҹзҺҜеўғеҸҳж•°пјҢд»Һе…¶дёӯжҸҗеҸ–еҹ еҸ· (й»ҳи®Өдёә \"8080\")\n* ''credentials'' - еҮӯиҜҒ CSV ж–Үд»¶зҡ„и·Ҝеҫ„еҗҚпјҲзӣёеҜ№дәҺз»ҙеҹәж–Үд»¶еӨ№пјү\n* ''anon-username'' - еҢҝеҗҚз”ЁжҲ·зҡ„зј–иҫ‘зҪІеҗҚ\n* ''username'' - еҸҜйҖүзҡ„еҹәжң¬йӘҢиҜҒз”ЁжҲ·еҗҚз§°\n* ''password'' - еҸҜйҖүзҡ„еҹәжң¬йӘҢиҜҒеҜҶз Ғ\n* ''authenticated-user-header'' - еҸҜйҖүзҡ„ж ҮеӨҙеҗҚз§°пјҢз”ЁдәҺеҸ—дҝЎд»»иә«д»ҪйӘҢиҜҒ\n* ''readers'' - е…Ғи®ёиҜ»еҸ–жӯӨз»ҙеҹәзҡ„дё»дҪ“пјҢд»ҘйҖ—еҸ·еҲҶйҡ”зҡ„жё…еҚ•\n* ''writers'' - е…Ғи®ёеҶҷе…ҘжӯӨз»ҙеҹәзҡ„дё»дҪ“пјҢд»ҘйҖ—еҸ·еҲҶйҡ”зҡ„жё…еҚ•\n* ''csrf-disable'' - и®ҫзҪ®дёә \"yes\" д»ҘзҰҒз”Ё CSRF жЈҖжҹҘ (й»ҳи®Өдёә \"no\")\n* ''sse-enabled'' - и®ҫзҪ®дёә \"yes\" д»ҘеҗҜз”ЁжңҚеҠЎеҷЁдј йҖҒзҡ„дәӢд»¶ (й»ҳи®Өдёә \"no\")\n* ''root-tiddler'' - жңҚеҠЎзҡ„еҹәжң¬жқЎзӣ® (й»ҳи®Өдёә \"$:/core/save/all\")\n* ''root-render-type'' - е‘ҲзҺ°зҡ„еҹәжң¬жқЎзӣ®зҡ„еҶ…е®№зұ»еһӢ (й»ҳи®Өдёә \"text/plain\")\n* ''root-serve-type'' - жңҚеҠЎзҡ„еҹәжң¬жқЎзӣ®зҡ„еҶ…е®№зұ»еһӢ (й»ҳи®Өдёә \"text/html\")\n* ''tls-cert'' - TLS иҜҒд№Ұж–Үд»¶зҡ„и·Ҝеҫ„еҗҚпјҲзӣёеҜ№дәҺз»ҙеҹәж–Үд»¶еӨ№пјү\n* ''tls-key'' - TLS еҜҶй’Ҙж–Үд»¶зҡ„и·Ҝеҫ„еҗҚпјҲзӣёеҜ№дәҺз»ҙеҹәж–Үд»¶еӨ№пјү\n* ''debug-level'' - еҸҜйҖүзҡ„и°ғиҜ•зә§еҲ«пјӣи®ҫзҪ®дёә \"debug\" жқҘжҹҘзңӢиҜ·жұӮзҡ„иҜҰз»ҶдҝЎжҒҜпјӣ(й»ҳи®Өдёә \"none\")\n* ''gzip'' - и®ҫдёә \"yes\" д»ҘеҗҜз”Ёжҹҗдәӣ http з«ҜзӮ№зҡ„ gzip еҺӢзј© (й»ҳи®Өдёә \"no\")\n\nжңүе…іеҗ‘ж•ҙдёӘжң¬ең°зҪ‘з»ңејҖеҗҜе®һдҫӢзҡ„дҝЎжҒҜпјҢд»ҘеҸҠеҸҜиғҪзҡ„е®үе…Ёй—®йўҳпјҢиҜ·еҸӮйҳ… TiddlyWiki.com зҡ„ WebServer жқЎзӣ®гҖӮ\n"
        },
        "$:/language/Help/load": {
            "title": "$:/language/Help/load",
            "description": "д»Һж–Үд»¶дёӯеҠ иҪҪжқЎзӣ®",
            "text": "д»Һ TiddlyWiki (`.html`), `.tiddler`, `.tid`, `.json` жҲ–е…¶д»–жң¬жңәж–Үд»¶еҠ иҪҪжқЎзӣ®гҖӮеә”з”Ёзҡ„еӨ„зҗҶзЁӢеәҸеҸ–еҶідәҺеҜје…Ҙж–Үд»¶зҡ„жү©еұ•еҗҚгҖӮеҰӮжһңжӮЁйңҖиҰҒжҳҺзЎ®жҢҮе®ҡи§ЈдёІеҷЁе’Ңзј–з ҒпјҢиҜ·ж”№з”Ё `import` е‘Ҫд»ӨгҖӮ\n\n```\n--load <filepath> [noerror]\n--load <dirpath> [noerror]\n```\n\nй»ҳи®Өжғ…еҶөдёӢ, еҰӮжһңжңӘжүҫеҲ°жқЎзӣ®пјҢload е‘Ҫд»Өдјҡеј•еҸ‘й”ҷиҜҜгҖӮйҖҡиҝҮжҸҗдҫӣеҸҜйҖүзҡ„ \"noerror\" еҸӮж•°еҸҜд»ҘжҠ‘еҲ¶иҜҘй”ҷиҜҜгҖӮ\n\nд»Һе·ІеҠ еҜҶзҡ„ TiddlyWiki ж–Үд»¶дёӯеҠ иҪҪжқЎзӣ®пјҢйЎ»дҪҝз”Ё PasswordCommand жҢҮе®ҡеҜҶз ҒпјҢдҫӢеҰӮпјҡ\n\n```\ntiddlywiki ./MyWiki --password pa55w0rd --load my_encrypted_wiki.html\n```\n\nиҜ·жіЁж„Ҹ TiddlyWiki е°ҶдёҚеҠ иҪҪж—§зүҲжң¬зҡ„е·ІжҢӮиҪҪзҡ„жҸ’д»¶гҖӮ\n"
        },
        "$:/language/Help/makelibrary": {
            "title": "$:/language/Help/makelibrary",
            "description": "жһ„е»әеҚҮзә§еӨ„зҗҶжүҖйңҖзҡ„зЁӢејҸеә“жҸ’д»¶",
            "text": "дёәеҚҮзә§еӨ„зҗҶжһ„е»ә `$:/UpgradeLibrary` жқЎзӣ®гҖӮ\n\nеҚҮзә§зЁӢејҸеә“иў«ж јејҸеҢ–дёәдёҖдёӘжҸ’д»¶зұ»еһӢдёә `library` зҡ„дёҖиҲ¬жҸ’д»¶жқЎзӣ®гҖӮе®ғеҢ…еҗ« TiddlyWiki5 еӯҳеӮЁеә“дёӯжүҖжңүеҸҜз”Ёзҡ„жҸ’д»¶гҖҒеёғжҷҜдё»йўҳе’ҢиҜӯиЁҖеҢ…зҡ„еүҜжң¬гҖӮ\n\nжӯӨе‘Ҫд»Өд»…дҫӣеҶ…йғЁдҪҝз”Ёпјӣе®ғеҸӘжҳҜдёҺдҪҝз”ЁиҖ…жһ„е»әдёҖдёӘиҮӘи®ўзҡ„еҚҮзә§зЁӢеәҸзӣёе…ігҖӮ\n\n```\n--makelibrary <title>\n```\n\nж ҮйўҳеҸӮж•°й»ҳи®Өдёә `$:/UpgradeLibrary`гҖӮ\n"
